const minuteMs = 60 * 1000;
const hourMs = 60 * minuteMs;

function offsetDateString(targetMs: number, offsetMinutes: number): string {
  const offsetSign = offsetMinutes >= 0 ? '+' : '-';
  const absoluteMinutes = Math.abs(offsetMinutes);
  const offsetHours = Math.floor(absoluteMinutes / 60);
  const offsetRemainderMinutes = absoluteMinutes % 60;
  const adjusted = new Date(targetMs + offsetMinutes * 60 * 1000);

  const year = adjusted.getUTCFullYear();
  const month = String(adjusted.getUTCMonth() + 1).padStart(2, '0');
  const day = String(adjusted.getUTCDate()).padStart(2, '0');
  const hours = String(adjusted.getUTCHours()).padStart(2, '0');
  const minutes = String(adjusted.getUTCMinutes()).padStart(2, '0');
  const seconds = String(adjusted.getUTCSeconds()).padStart(2, '0');

  return `${year}-${month}-${day}T${hours}:${minutes}:${seconds}${offsetSign}${String(
    offsetHours
  ).padStart(2, '0')}:${String(offsetRemainderMinutes).padStart(2, '0')}`;
}

